import api from "@/api/app/client";

/**
 * Fetches a file from the API with authorization headers and returns a blob URL
 * This is necessary because standard <img> tags cannot include Authorization headers
 * @param fileId - The ID of the file to fetch
 * @returns A blob URL that can be used in src attribute, or null if fetch fails
 */
export async function getAuthorizedFileUrl(fileId: string | undefined): Promise<string | null> {
  if (!fileId) return null;

  try {
    const response = await api.get(`/files/${fileId}`, {
      responseType: 'blob'
    });

    return URL.createObjectURL(response.data);
  } catch (error) {
    console.error(`Error fetching authorized file URL for ${fileId}:`, error);
    return null;
  }
}

/**
 * Cleans up a blob URL created by getAuthorizedFileUrl
 * Call this when the URL is no longer needed to free memory
 * @param blobUrl - The blob URL to clean up
 */
export function cleanupBlobUrl(blobUrl: string | null): void {
  if (blobUrl) {
    URL.revokeObjectURL(blobUrl);
  }
}
