import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import HarmonyForm from "@/components/forms/HarmonyForm";
import type { Customer } from "@/types/customer";
import type { Project } from "@/types/project";

interface CustomerFormDialogProps {
  open: boolean;
  onClose: () => void;
  formType: "CustomerDTO" | "ProjectDTO" | "";
  isEditMode: boolean;
  editData: Customer | Project | null;
  onSubmit: (data: Record<string, any>) => void | Promise<void>;
  isSubmitting?: boolean;
}

export function CustomerFormDialog({
  open,
  onClose,
  formType,
  isEditMode,
  editData,
  onSubmit,
  isSubmitting = false,
}: CustomerFormDialogProps) {
  if (!formType) return null;

  const isProject = formType === "ProjectDTO";
  const title = isEditMode ? "Edit Record" : "New Registration";

  const initialValues = editData && isEditMode
    ? (isProject
        ? { ...editData, startDate: (editData as Project).startDate?.split('T')[0] || "", endDate: (editData as Project).endDate?.split('T')[0] || "" }
        : editData)
    : undefined;

  return (
    <HarmonyDialog
      open={open}
      onOpenChange={(o) => { if (!o) onClose(); }}
      title={title}
      onSubmit={() => document.querySelector('form')?.requestSubmit?.()}
      submitLabel={isEditMode ? "Save Changes" : "Create"}
      isSubmitting={isSubmitting}
    >
      <HarmonyForm
        key={`${formType}-${isEditMode ? editData?.id : 'new'}`}
        dtoName={formType}
        mode={isEditMode ? "edit" : "create"}
        onSubmit={onSubmit}
        initialValues={initialValues}
        hideSubmitButton={true}
      />
    </HarmonyDialog>
  );
}
